#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int *a = (int*)malloc(n * sizeof(int));
        int *b = (int*)malloc(m * sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &a[i]);
        for (int i = 0; i < m; ++i) scanf("%d", &b[i]);
        qsort(a, n, sizeof(int), cmp);
        qsort(b, m, sizeof(int), cmp);
        int i = 0, j = 0;
        int first = 1;
        while (i < n && j < m) {
            if (a[i] < b[j]) ++i;
            else if (a[i] > b[j]) ++j;
            else {
                if (first || (i > 0 && a[i] != a[i-1])) {
                    if (!first) printf(" ");
                    printf("%d", a[i]);
                    first = 0;
                }
                ++i; ++j;
            }
        }
        printf("\n");
        free(a);
        free(b);
    }
    return 0;
}

