const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const n = Number(input[idx++]);
  const m = Number(input[idx++]);
  const a = [];
  const b = [];
  for (let i = 0; i < n; i++) a.push(Number(input[idx++]));
  for (let i = 0; i < m; i++) b.push(Number(input[idx++]));
  a.sort((x, y) => x - y);
  b.sort((x, y) => x - y);
  let i = 0, j = 0;
  const res = [];
  while (i < n && j < m) {
    if (a[i] < b[j]) i++;
    else if (a[i] > b[j]) j++;
    else {
      if (res.length === 0 || res[res.length - 1] !== a[i]) res.push(a[i]);
      i++; j++;
    }
  }
  outputs.push(res.join(' '));
}
